import scala.collection.mutable

def solve(n: Long, k: Long): Long = {
    if (k == 0) {
        if (n >= 1) 1 else 0
    } else {
        val memo = mutable.Map[(Long, Int), Long]()

        def countNumbers(numBits: Int, remainingDepth: Int, isTight: Boolean, bits: Array[Char]): Long = {
            if (numBits == bits.length) {
                if (remainingDepth == 0) 1 else 0
            } else if (!isTight && memo.contains((numBits.toLong, remainingDepth))) {
                memo((numBits.toLong, remainingDepth))
            } else {
                val limit = if (isTight) bits(numBits) - '0' else 1
                var total = 0L
                for (bit <- 0 to limit) {
                    val newIsTight = isTight && (bit == limit)
                    if (bit == 0) {
                        total += countNumbers(numBits + 1, remainingDepth, newIsTight, bits)
                    } else {
                        if (remainingDepth > 0) {
                            total += countNumbers(numBits + 1, remainingDepth - 1, newIsTight, bits)
                        }
                    }
                }
                if (!isTight) {
                    memo((numBits.toLong, remainingDepth)) = total
                }
                total
            }
        }

        def popcountDepth(x: Long): Int = {
            var depth = 0
            var current = x
            while (current != 1) {
                current = java.lang.Long.bitCount(current)
                depth += 1
            }
            depth
        }

        if (k == 0) {
            if (n >= 1) 1 else 0
        } else {
            val bits = n.toBinaryString.toCharArray
            val totalWithDepthK = countNumbers(0, k.toInt, isTight = true, bits)

            if (k == 1) {
                totalWithDepthK
            } else {
                val totalWithDepthKMinus1 = countNumbers(0, (k - 1).toInt, isTight = true, bits)
                totalWithDepthK - totalWithDepthKMinus1
            }
        }
    }
}
