def solve(n: Long, k: Long): Long = {
    if (k == 0) {
        return if (n >= 1) 1 else 0
    }

    // Precompute the popcount-depth for numbers up to a certain limit (like 60 bits)
    val maxBits = 60
    val depth = Array.ofDim[Int](maxBits + 1)
    depth(1) = 0
    for (i <- 2 to maxBits) {
        depth(i) = depth(Integer.bitCount(i)) + 1
    }

    // Memoization for the DP
    val memo = scala.collection.mutable.Map[(Int, Int, Int, Boolean), Long]()

    def dp(pos: Int, cnt: Int, targetDepth: Int, tight: Boolean, num: String): Long = {
        if (pos == num.length) {
            if (cnt == 0) 0 else {
                if (depth(cnt) == targetDepth) 1 else 0
            }
        } else {
            val key = (pos, cnt, targetDepth, tight)
            if (memo.contains(key)) return memo(key)

            val limit = if (tight) num(pos) - '0' else 1
            var res = 0L

            for (d <- 0 to limit) {
                val newTight = tight && (d == limit)
                val newCnt = cnt + (if (d == 1) 1 else 0)
                res += dp(pos + 1, newCnt, targetDepth, newTight, num)
            }

            memo(key) = res
            res
        }
    }

    val binary = n.toBinaryString
    val res = dp(0, 0, k.toInt, true, binary)

    // Subtract numbers with depth k-1 if k > 1
    if (k > 1) {
        memo.clear()
        val resKMinus1 = dp(0, 0, (k - 1).toInt, true, binary)
        res - resKMinus1
    } else {
        res
    }
}
